   539|  const roomId = sessionRoomId(sessionId);
   540|  const ownerCheckMessages = publicChatHistoryStorage.listMessages(roomId, MAX_SESSION_HISTORY_LIMIT);
   541|  const sessionBelongsToClient = ownerCheckMessages.length === 0 || ownerCheckMessages.some((message) => message.username === clientId);
   542|
   543|  if (!sessionBelongsToClient) {
